#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long sum = 0;
        long long product = 1;
        for (int i = 0; i < N; ++i) {
            int x;
            scanf("%d", &x);
            sum += x;
            product *= x;
        }
        printf("%lld %lld\n", sum, product);
    }
    return 0;
}

